import React, { useEffect, useState } from "react";
import api from "../services/axios";

function Dashboard() {
  const [breaches, setBreaches] = useState([]);
  const [error, setError] = useState(null);

  useEffect(() => {
    const fetchBreaches = async () => {
      try {
        const response = await api.get("/breaches/");
        setBreaches(response.data);
      } catch (error) {
        console.error("Error fetching breach data", error);
        setError("Failed to load breach data. Please try again later.");
      }
    };
    fetchBreaches();
  }, []);

  return (
    <div className="dashboard">
      <h2>Security Dashboard</h2>
      {error ? (
        <div className="error-message">{error}</div>  // Show error message
      ) : (
        <div>
          <h3>Recent Breaches</h3>
          <ul>
            {breaches.map((breach) => (
              <li key={breach.id}>
                {breach.name} - {breach.status}
              </li>
            ))}
          </ul>
        </div>
      )}
    </div>
  );
}

export default Dashboard;
